data.output:
240			}
241			noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
242			if countErr != nil {
243				return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
244			}
245			noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)
246			if adjErr != nil {
247				return Outcome{Report: report, StoreErrOp: "adjudicateNoChanges", StoreErr: adjErr}, nil
248			}
249			return Outcome{
250				Report:      adjudicatedReport,
251				Disposition: OutcomeReported,
252				NoChanges:   &noChangesOut,
253			}, nil
254		}
255	
256		if report.Status == StatusDeclinedNeedsDecomposition {
257			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
258			report.RetryAfter = parkUntil.Format(time.RFC3339)
259			event := buildDecompositionParkingEvent(report)
260			return Outcome{
261				Report:      report,
262				Disposition: OutcomePark,
263				Parking: &ParkingOutcome{
264					Unclaim:              true,
265					RetryAfter:           parkUntil,
266					RunPostAttemptTriage: true,
267					Event:                event,
268				},
269			}, nil
270		}
271	
272		if report.Status == StatusPushConflict {
273			parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
274			report.RetryAfter = parkUntil.Format(time.RFC3339)
275			event := buildPushConflictParkingEvent(report)
276			return Outcome{
277				Report:      report,
278				Disposition: OutcomePark,
279				Parking: &ParkingOutcome{
280					Unclaim:              true,
281					RetryAfter:           parkUntil,
282					RunPostAttemptTriage: true,
283					Event:                event,
284				},
285			}, nil
286		}
287	
288		return Outcome{Report: report, Disposition: OutcomeReported}, err
289	}
290	
291	func nowFn(fn func() time.Time) time.Time {
292		if fn != nil {
293			return fn()
294		}
295		return time.Now()
296	}
297	
298	const maxAttemptCooldown = 24 * time.Hour
