95	// ValidateLifecycleTransition returns nil when from -> to is a valid persisted
96	// status transition under the supplied explicit facts.
97	func ValidateLifecycleTransition(from, to string, opts LifecycleTransitionOptions) error {
98		if err := validateLifecycleStatus(from); err != nil {
99			return err
100		}
101		if err := validateLifecycleStatus(to); err != nil {
102			return err
103		}
104		if from == to {
105			return nil
106		}
107		if to == StatusClosed && opts.ManualClose {
108			switch from {
109			case StatusOpen, StatusInProgress, StatusBlocked, StatusProposed:
110				return nil
111			}
112		}
113		if from == StatusClosed && to == StatusOpen && opts.ManualReopen {
114			return nil
115		}
116		if from == StatusClosed || from == StatusCancelled {
117			return lifecycleTransitionError(LifecycleIssueTransitionFromTerminal, from, to)
118		}
119		if to == StatusProposed && !opts.OperatorRequired {
120			return lifecycleTransitionError(LifecycleIssueTransitionRequiresOperator, from, to)
121		}
122		if to == StatusBlocked && strings.TrimSpace(opts.ExternalBlockerReason) == "" {
123			return lifecycleTransitionError(LifecycleIssueTransitionRequiresExternal, from, to)
124		}
125		if lifecycleTransitionAllowed(from, to) {
126			return nil
127		}
128		return lifecycleTransitionError(LifecycleIssueTransitionUnsupported, from, to)
129	}
130	
131	// CanLifecycleTransition is a convenience predicate around
132	// ValidateLifecycleTransition.
133	func CanLifecycleTransition(from, to string, opts LifecycleTransitionOptions) bool {
134		return ValidateLifecycleTransition(from, to, opts) == nil
135	}
136	
137	// LifecycleStatusSatisfiesDependency reports whether a persisted status
138	// satisfies dependent beads. Only closed satisfies dependents.
139	func LifecycleStatusSatisfiesDependency(status string) bool {
140		return status == StatusClosed
141	}
142	
143	// LifecycleDependenciesSatisfied reports whether every dependency is closed.
144	func LifecycleDependenciesSatisfied(deps []LifecycleDependencyState) bool {
145		for _, dep := range deps {
146			if !LifecycleStatusSatisfiesDependency(dep.Status) {
147				return false
148			}
149		}
150		return true
151	}
152	
153	// EvaluateLifecycleQueue derives queue state from caller-provided facts. Legacy
154	// lifecycle labels are reported as warnings only; they never choose the bucket.
155	func EvaluateLifecycleQueue(f LifecycleQueueFacts) LifecycleQueueDecision {
156		decision := LifecycleQueueDecision{
157			DependenciesSatisfied: LifecycleDependenciesSatisfied(f.Dependencies),
158			SatisfiesDependents:   LifecycleStatusSatisfiesDependency(f.Status),
159		}
160		decision.Warnings = append(decision.Warnings, lifecycleLegacyLabelWarnings(f.LegacyLabels)...)
161		for _, warning := range f.LegacyMigrationWarnings {
162			trimmed := strings.TrimSpace(warning)
163			if trimmed == "" {
164				continue
165			}
166			decision.Issues = append(decision.Issues, LifecycleIssue{
167				Code:   LifecycleIssueLegacyMigrationCompatibility,
168				Detail: trimmed,
169			})
170			decision.Warnings = append(decision.Warnings, trimmed)
171		}
172	
173		if err := validateLifecycleStatus(f.Status); err != nil {
174			decision.Bucket = LifecycleBucketInvalid
175			decision.Issues = append(decision.Issues, LifecycleIssue{
176				Code:   LifecycleIssueInvalidStatus,
177				Detail: err.Error(),
178			})
179			return decision
180		}
181	
182		switch f.Status {
183		case StatusClosed:
184			decision.Bucket = LifecycleBucketClosedTerminal
185		case StatusCancelled:
186			decision.Bucket = LifecycleBucketCancelledTerminal
187		case StatusProposed:
188			decision.Bucket = LifecycleBucketProposed
189			decision.OperatorAttention = true
190		case StatusInProgress:
191			if f.ClaimFresh {
192				decision.Bucket = LifecycleBucketClaimed
193				return decision
194			}
195			decision = evaluateOpenLifecycleQueue(f, decision)
196		case StatusBlocked:
197			decision.Bucket = LifecycleBucketBlockedExternal
198			decision.ExternalBlockerReason = strings.TrimSpace(f.ExternalBlockerReason)
199			if decision.ExternalBlockerReason == "" {
200				decision.Issues = append(decision.Issues, LifecycleIssue{
201					Code:   LifecycleIssueBlockedMissingExternalReason,
202					Detail: "blocked status requires an explicit external blocker reason",
203				})
204			}
205		case StatusOpen:
206			decision = evaluateOpenLifecycleQueue(f, decision)
207		}
208		return decision
209	}
210	
211	func evaluateOpenLifecycleQueue(f LifecycleQueueFacts, decision LifecycleQueueDecision) LifecycleQueueDecision {
212		if !decision.DependenciesSatisfied {
213			decision.Bucket = LifecycleBucketWaitingDependencies
214			return decision
215		}
216		if strings.TrimSpace(f.SupersededBy) != "" {
217			decision.Bucket = LifecycleBucketSuperseded
218			return decision
219		}
220		if f.EpicContainer {
221			decision.Bucket = LifecycleBucketEpicContainer
222			return decision
223		}
224		if f.RetryCooldownActive {
225			decision.Bucket = LifecycleBucketRetryCooldown
226			return decision
227		}
228		if f.ExecutionEligibleKnown && !f.ExecutionEligible {
229			decision.Bucket = LifecycleBucketNotEligible
230			return decision
231		}
232		decision.Bucket = LifecycleBucketReady
233		decision.WorkerEligible = true
234		return decision
235	}
