101	// ReconcilePlan is a single proposed or applied lifecycle repair.
102	type ReconcilePlan struct {
103		BeadID         string         `json:"bead_id"`
104		Reason         string         `json:"reason"`
105		CurrentFields  map[string]any `json:"current_fields,omitempty"`
106		SetFields      map[string]any `json:"set_fields,omitempty"`
107		ClearFields    []string       `json:"clear_fields,omitempty"`
108		RemoveLabels   []string       `json:"remove_labels,omitempty"`
