114	// ReconcileLifecycleMetadata returns conservative repairs for stale
115	// no_changes management fields. With Apply=false it is a dry run; with
116	// Apply=true it mutates through the Store API and appends reconciliation
117	// evidence.
118	func (s *Store) ReconcileLifecycleMetadata(opts ReconcileOptions) ([]ReconcilePlan, error) {
119		if opts.Now.IsZero() {
120			opts.Now = time.Now().UTC()
121		}
122		beads, err := s.ReadAll()
123		if err != nil {
124			return nil, err
125		}
126		childrenByParent := make(map[string]int)
127		idFilter := make(map[string]bool, len(opts.IDs))
128		for _, id := range opts.IDs {
129			if strings.TrimSpace(id) != "" {
130				idFilter[strings.TrimSpace(id)] = true
131			}
132		}
133		for _, b := range beads {
134			if b.Parent != "" {
135				childrenByParent[b.Parent]++
136			}
137		}
138	
139		var plans []ReconcilePlan
140		for _, b := range beads {
141			if len(idFilter) > 0 && !idFilter[b.ID] {
142				continue
143			}
144			events, _ := s.eventsForBead(&b)
145			if p, ok := planLifecycleReconcile(b, events, childrenByParent[b.ID], opts.Now); ok {
146				if opts.Apply {
147					if err := s.applyReconcilePlan(p); err != nil {
148						return plans, err
149					}
150					p.Applied = true
151				}
152				plans = append(plans, p)
153			}
154		}
155		return plans, nil
156	}
