158	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount int, now time.Time) (ReconcilePlan, bool) {
159		p := ReconcilePlan{
160			BeadID:        b.ID,
161			CurrentFields: currentLifecycleFields(b),
162		}
163		latest := latestLifecycleEvent(events)
164	
165		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
166			p.Reason = "closed bead has stale no_changes lifecycle metadata"
167			p.ClearFields = noChangesFieldsPresent(b)
168			p.RemoveLabels = noChangesLabelsPresent(b)
169			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
170		}
171	
172		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
173			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
174			p.ClearFields = noChangesFieldsPresent(b)
175			p.RemoveLabels = noChangesLabelsPresent(b)
176			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
177		}
178	
179		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
180			p.Reason = "verified no_changes evidence closes as already_satisfied"
181			p.ClearFields = noChangesFieldsPresent(b)
182			p.RemoveLabels = noChangesLabelsPresent(b)
183			p.CloseSatisfied = true
184			return p, true
185		}
186	
187		if isExpiredRetryAfter(b, now) {
188			p.Reason = "expired retry-after metadata no longer blocks execution"
189			p.ClearFields = []string{ExtraRetryAfter}
190			return p, true
191		}
192	
193		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
194			if b.Extra != nil {
195				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
196					return ReconcilePlan{}, false
197				}
198			}
199			p.Reason = "parent/epic work is owned by child beads"
200			p.SetFields = map[string]any{
201				ExtraExecutionElig:   false,
202				ExtraExecutionReason: "parent/epic container; execute child beads first",
203			}
204			return p, true
205		}
206	
207		return ReconcilePlan{}, false
208	}
209	
210	func (s *Store) applyReconcilePlan(p ReconcilePlan) error {
211		mutate := func(b *Bead) error {
212			if b.Extra == nil {
213				b.Extra = make(map[string]any)
214			}
215			for _, key := range p.ClearFields {
216				delete(b.Extra, key)
217			}
218			for key, value := range p.SetFields {
219				b.Extra[key] = value
220			}
221			for _, label := range p.RemoveLabels {
222				removeLabel(b, label)
223			}
224			for _, label := range p.AddLabels {
225				addLabel(b, label)
226			}
227			addLabel(b, LabelReconciledNoChangesState)
228			appendInlineEvent(b, BeadEvent{
229				Kind:      "lifecycle_reconciled",
230				Summary:   p.Reason,
231				Actor:     "ddx",
232				Source:    "ddx bead reconcile",
233				CreatedAt: time.Now().UTC(),
234			})
235			return nil
236		}
237		var err error
238		// TD-031 §5: reconcile-close is a meta-close that intentionally bypasses
239		// ClosureGate — the bead has no execution session and no closing_commit_sha
240		// of its own; every transitive dependency is closed, supplying evidence by reference.
241		if p.CloseSatisfied {
242			err = s.UpdateWithLifecycleStatus(p.BeadID, StatusClosed, LifecycleTransitionOptions{
243				ManualClose: true,
244				Reason:      p.Reason,
245				Actor:       "ddx",
246				Source:      "ddx bead reconcile",
247			}, mutate)
248		} else {
249			err = s.Update(p.BeadID, func(b *Bead) {
250				_ = mutate(b)
251			})
252		}
253		if err != nil {
254			return err
255		}
256		if p.CloseSatisfied {
257			return s.externalizeEvents(p.BeadID)
258		}
259		return nil
260	}
261	
262	func appendInlineEvent(b *Bead, event BeadEvent) {
263		if event.CreatedAt.IsZero() {
264			event.CreatedAt = time.Now().UTC()
265		}
266		events := decodeBeadEvents(b.Extra["events"])
267		events = append(events, event)
268		b.Extra["events"] = encodeEventsForExtra(events)
269	}
