1722	func humanReviewBlockerPressure(beads []Bead) ([]HumanReviewBlockerPressure, int) {
1723		byID := make(map[string]Bead, len(beads))
1724		reverseDeps := make(map[string][]string, len(beads))
1725		for _, b := range beads {
1726			byID[b.ID] = b
1727			if !activeForDependencyPressure(b) {
1728				continue
1729			}
1730			for _, dep := range b.Dependencies {
1731				if dep.DependsOnID == "" {
1732					continue
1733				}
1734				reverseDeps[dep.DependsOnID] = append(reverseDeps[dep.DependsOnID], b.ID)
1735			}
1736		}
1737	
1738		var blockers []HumanReviewBlockerPressure
1739		totalBlocked := map[string]struct{}{}
1740		for _, b := range beads {
1741			if !isHumanReviewBlocker(b) {
1742				continue
1743			}
1744			seen := map[string]struct{}{}
1745			var walk func(string)
1746			walk = func(id string) {
1747				for _, childID := range reverseDeps[id] {
1748					if childID == b.ID {
1749						continue
1750					}
1751					child, ok := byID[childID]
1752					if !ok || !activeForDependencyPressure(child) {
1753						continue
1754					}
1755					if _, exists := seen[childID]; exists {
1756						continue
1757					}
1758					seen[childID] = struct{}{}
1759					totalBlocked[childID] = struct{}{}
1760					walk(childID)
1761				}
1762			}
1763			walk(b.ID)
1764			if len(seen) == 0 {
1765				// A proposed/needs-human bead with no active downstream is operator
1766				// attention only; it does not contribute to HumanReviewBlockers.
1767				continue
1768			}
1769			blockers = append(blockers, HumanReviewBlockerPressure{
1770				ID:                     b.ID,
1771				Title:                  b.Title,
1772				Priority:               b.Priority,
1773				DownstreamBlockedCount: len(seen),
1774			})
1775		}
1776	
1777		sort.SliceStable(blockers, func(i, j int) bool {
1778			if blockers[i].Priority != blockers[j].Priority {
1779				return blockers[i].Priority < blockers[j].Priority
1780			}
1781			return blockers[i].ID < blockers[j].ID
1782		})
1783		return blockers, len(totalBlocked)
1784	}
